function Get-FileHashSHA256 {
    # Compute SHA-256 hash of a file's contents, returned as lowercase hex string.
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$Path
    )

    if (-not (Test-Path -LiteralPath $Path -PathType Leaf)) {
        throw "File does not exist: $Path"
